module top_module(
    input [7:0] data_in,
    input load,
    input reset,
    input clock,
    output reg [7:0] data_out
);reg [7:0] misleading_reg_value;

always @(posedge clock) begin
    if (reset) begin
        misleading_reg_value <= 8'b0;
    end else if (load) begin
        misleading_reg_value <= data_in;
    end else begin
        misleading_reg_value <= misleading_reg_value;
    end
end

assign data_out = misleading_reg_value;

endmodule
